export function initialize(sentinel, dotNetHelper) {
    const observer = new IntersectionObserver(async (entries) => {
        if (entries[0].isIntersecting) {
            await dotNetHelper.invokeMethodAsync("OnSentinelVisible");
        }
    }, { rootMargin: "200px" });

    observer.observe(sentinel);

    return observer;
}

export function dispose(observer, sentinel) {
    observer.unobserve(sentinel);
    observer.disconnect();
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner"></div>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    private ElementReference sentinelRef;
    private IJSObjectReference? module;
    private IJSObjectReference? observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-8320c4de7e824b4788670b9efb6a373c/Components/InfiniteScrollList.razor.js");
        }

        // (Re)attach the observer whenever HasMore becomes true and the sentinel is rendered
        if (HasMore && module is not null && observer is null)
        {
            dotNetRef ??= DotNetObjectReference.Create(this);
            observer = await module.InvokeAsync<IJSObjectReference>(
                "initialize", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore)
            return;

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;

        if (!HasMore)
        {
            await DisposeObserverAsync();
        }

        StateHasChanged();
    }

    private async Task DisposeObserverAsync()
    {
        if (observer is not null && module is not null)
        {
            await module.InvokeVoidAsync("dispose", observer, sentinelRef);
            observer = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await DisposeObserverAsync();
        dotNetRef?.Dispose();

        if (module is not null)
        {
            await module.DisposeAsync();
        }
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 3px solid rgba(0, 0, 0, 0.1);
    border-top-color: #0d6efd;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.8s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

